import{_ as a,c as t,o as r,a4 as e}from"./chunks/framework.HaEZziQ1.js";const i="/FrontEndLearnNotes/assets/浏览器工作原理.DElY3fOU.png",l="/FrontEndLearnNotes/assets/浏览器渲染过程.7EWuY7s8.jpg",o="/FrontEndLearnNotes/assets/浏览器内核和JavaScript引擎的关系.DxWNkxRG.jpg",n="/FrontEndLearnNotes/assets/小程序的引擎架构.DyU7zwEj.jpg",s="/FrontEndLearnNotes/assets/V8引擎原理图.CywPaJt6.jpg",c="/FrontEndLearnNotes/assets/v8引擎的官方解析图.DNM7q3qN.jpg",f=JSON.parse('{"title":"JavaScript的运行环境","description":"","frontmatter":{},"headers":[],"relativePath":"Document/JavaScript笔记/JavaScript的运行和原理/JavaScript的运行环境.md","filePath":"Document/JavaScript笔记/JavaScript的运行和原理/JavaScript的运行环境.md","lastUpdated":1709668918000}'),p={name:"Document/JavaScript笔记/JavaScript的运行和原理/JavaScript的运行环境.md"},h=e('<h1 id="javascript的运行环境" tabindex="-1">JavaScript的运行环境 <a class="header-anchor" href="#javascript的运行环境" aria-label="Permalink to &quot;JavaScript的运行环境&quot;">​</a></h1><h2 id="浏览器的工作原理、核心" tabindex="-1">浏览器的工作原理、核心 <a class="header-anchor" href="#浏览器的工作原理、核心" aria-label="Permalink to &quot;浏览器的工作原理、核心&quot;">​</a></h2><h3 id="浏览器工作原理图例" tabindex="-1">浏览器工作原理图例 <a class="header-anchor" href="#浏览器工作原理图例" aria-label="Permalink to &quot;浏览器工作原理图例&quot;">​</a></h3><p><img src="'+i+'" alt="浏览器工作原理"></p><h3 id="浏览器内核" tabindex="-1">浏览器内核 <a class="header-anchor" href="#浏览器内核" aria-label="Permalink to &quot;浏览器内核&quot;">​</a></h3><p>我们经常会说：不同的浏览器有不同的内核组成</p><ul><li><strong>Gecko</strong>：早期被Netscape和Mozilla Firefox浏览器浏览器使用；</li><li><strong>Trident</strong>：微软开发，被IE4~IE11浏览器使用，但是Edge浏览器已经转向Blink；</li><li><strong>Webkit</strong>：苹果基于KHTML开发、开源的，用于Safari，Google Chrome之前也在使用；</li><li><strong>Blink</strong>：是Webkit的一个分支，Google开发，目前应用于Google Chrome、Edge、Opera等;</li></ul><p>事实上，我们经常说的浏览器内核指的是浏览器的排版引擎</p><ul><li><strong>排版引擎</strong>(layout engine)，也称为<strong>浏览器引擎</strong>( browser engine )、<strong>页面染引擎</strong>(rendering engine)或<strong>样版引擎</strong>。</li></ul><h3 id="浏览器渲染过程" tabindex="-1">浏览器渲染过程 <a class="header-anchor" href="#浏览器渲染过程" aria-label="Permalink to &quot;浏览器渲染过程&quot;">​</a></h3><p>但是在浏览器执行过程中，HTML解析的时候遇到了JavaScript标签，应该怎么办呢? 会停止解析HTML，而去加载和执行JavaScript代码<img src="'+l+'" alt="浏览器渲染过程"></p><h2 id="javascript引擎的解析" tabindex="-1">JavaScript引擎的解析 <a class="header-anchor" href="#javascript引擎的解析" aria-label="Permalink to &quot;JavaScript引擎的解析&quot;">​</a></h2><h3 id="javascript引擎就是-执行javascript的代码" tabindex="-1">JavaScript引擎就是 执行JavaScript的代码 <a class="header-anchor" href="#javascript引擎就是-执行javascript的代码" aria-label="Permalink to &quot;JavaScript引擎就是 执行JavaScript的代码&quot;">​</a></h3><ul><li>JavaScript是高级语言，高级的编程语言都是需要转成最终的机器指令来执行的</li><li>事实上我们编写的JavaScript无论你交给浏览器或者Node执行，最后都是需要被CPU执行的</li><li>但是CPU只认识自己的指令集，实际上是机器语言，才能被CPU所执行</li><li>所以我们需要<strong>JavaScript引擎</strong>帮助我们<strong>将JavaScript代码翻译成CPU指令来执行</strong></li></ul><h3 id="常见的javascript引擎" tabindex="-1">常见的JavaScript引擎 <a class="header-anchor" href="#常见的javascript引擎" aria-label="Permalink to &quot;常见的JavaScript引擎&quot;">​</a></h3><ul><li><strong>SpiderMonkey</strong>：第一款JavaScript引擎，由Brendan Eich开发(也就是JavaScript作者);</li><li><strong>Chakra</strong>：微软开发，用于IT浏览器;</li><li><strong>JavaScriptCore</strong>：WebKit中的JavaScript引擎，Apple公司开发</li><li><strong>V8</strong>：Google开发的强大JavaScript引擎，也帮助Chrome从众多浏览器中脱颖而出，Node和Chrome谷歌浏览器都是使用的这个引擎;</li></ul><h3 id="浏览器内核和javascript引擎的关系" tabindex="-1">浏览器内核和JavaScript引擎的关系 <a class="header-anchor" href="#浏览器内核和javascript引擎的关系" aria-label="Permalink to &quot;浏览器内核和JavaScript引擎的关系&quot;">​</a></h3><p>这里我们先以WebKit为例，WebKit事实上由两部分组成的</p><ul><li>WebCore：负责HTML解析、布局、染等等相关的工作</li><li>JavaScriptCore：解析、执行JavaScript代码;</li></ul><p><img src="'+o+'" alt="浏览器内核和JavaScript引擎的关系"></p><p>小程序的引擎架构</p><p><img src="'+n+'" alt="小程序的引擎架构"></p><h2 id="v8引擎的工作原理" tabindex="-1">V8引擎的工作原理 <a class="header-anchor" href="#v8引擎的工作原理" aria-label="Permalink to &quot;V8引擎的工作原理&quot;">​</a></h2><p>官方地址：<a href="https://developers.google.com/v8/" target="_blank" rel="noreferrer">https://developers.google.com/v8/</a></p><p>GitHub：<a href="https://github.com/v8/v8" target="_blank" rel="noreferrer">https://github.com/v8/v8</a></p><h3 id="v8引擎的介绍" tabindex="-1">V8引擎的介绍 <a class="header-anchor" href="#v8引擎的介绍" aria-label="Permalink to &quot;V8引擎的介绍&quot;">​</a></h3><ul><li>V8是用C ++编写的Google开源高性能JavaScript和WebAssembly引擎，它用于Chrome和Nodejs等。</li><li>它实现ECMAScript和WebAssembly，并在Windows 7或更高版本，macOS 10.12+和使用x64，IA-32，ARM或MIPS处理器的Linux系统上运行。</li><li>V8可以独立运行，也可以嵌入到任何C ++应用程序中。</li></ul><h4 id="v8引擎解析javascript代码原理" tabindex="-1">V8引擎解析JavaScript代码原理 <a class="header-anchor" href="#v8引擎解析javascript代码原理" aria-label="Permalink to &quot;V8引擎解析JavaScript代码原理&quot;">​</a></h4><p>AST抽象语法树生成网站：<a href="https://astexplorer.net/" target="_blank" rel="noreferrer">AST explorer</a></p><p><img src="'+s+'" alt="V8引擎原理图"></p><p>babel下：</p><p>语法树运行顺序：ts --&gt; js --&gt; ast --&gt; generate code --&gt; js代码</p><p>vue的编译顺序：vue template --&gt; ast --&gt; createVNode</p><p>ES6转ES5也是使用AST抽象语法树转换</p><h3 id="v8引擎解析的架构" tabindex="-1">V8引擎解析的架构 <a class="header-anchor" href="#v8引擎解析的架构" aria-label="Permalink to &quot;V8引擎解析的架构&quot;">​</a></h3><p>V8引擎本身的源码非常复杂，大概有超过100w行C++代码，通过了解它的架构，我们可以知道它是如何对JavaScript执行的：</p><p><strong>Parse</strong>模块会将JavaScript代码转换成AST(抽象语法树)，这是因为解释器并不直接认识JavaScript代码;</p><ul><li>如果函数没有被调用，那么是不会被转换成AST的</li><li>Parse的V8官方文档：<a href="https://v8.dev/blog/scanner" target="_blank" rel="noreferrer">https://v8.dev/blog/scanner</a></li></ul><p><strong>Ignition</strong>是一个解释器，会将AST转换成ByteCode(字节码)</p><ul><li>同时会收集TurboFan优化所需要的信息(比如函数参数的类型信息，有了类型才能进行真实的运算)</li><li>如果函数只调用一次，Ignition会执行解释执行ByteCode;</li><li>Ignition的V8官方文档：<a href="https://v8.dev/blog/ignition-interpreter" target="_blank" rel="noreferrer">https://v8.dev/blog/ignition-interpreter</a></li></ul><p><strong>TurboFan</strong>是一个编译器，可以将字节码编译为CPU可以直接执行的机器码;</p><ul><li>如果一个函数被多次调用，那么就会被标记为<strong>热点函数</strong>，那么就会经过TurboFan转换成优化的机器码，提高代码的执行性能</li><li>但是，<strong>机器码实际上也会被还原为Bvteode</strong>，这是因为如果后续执行函数的过程中，类型发生了变化(比如sum函数原来执行的是number类型，后来执行变成了string类型)，之前优化的机器码并不能正确的处理运算，就会逆向的转换成字节码；</li><li>TurboFan的V8官方文档：<a href="https://v8.dev/blog/turbofan-iit" target="_blank" rel="noreferrer">https://v8.dev/blog/turbofan-iit</a></li></ul><h3 id="v8引擎的官方解析图" tabindex="-1">V8引擎的官方解析图 <a class="header-anchor" href="#v8引擎的官方解析图" aria-label="Permalink to &quot;V8引擎的官方解析图&quot;">​</a></h3><p><img src="'+c+'" alt="v8引擎的官方解析图"></p><h3 id="v8引擎执行的细节" tabindex="-1">V8引擎执行的细节 <a class="header-anchor" href="#v8引擎执行的细节" aria-label="Permalink to &quot;V8引擎执行的细节&quot;">​</a></h3><h4 id="javascript源码是如何被解析-parse过程-的" tabindex="-1">JavaScript源码是如何被解析(Parse过程)的 <a class="header-anchor" href="#javascript源码是如何被解析-parse过程-的" aria-label="Permalink to &quot;JavaScript源码是如何被解析(Parse过程)的&quot;">​</a></h4><ul><li>1.Blink浏览器内核将源码交给V8引擎，Stream获取到源码并且进行编码转换;</li><li>2.Scanner会进行词法分析(lexicalanalysis)，词法分析会将代码转换成tokens;</li><li>3.接下来tokens会被转换成AST树，经过Parser和PreParser: <ul><li>Parser就是直接将tokens转成AST树架构;</li><li>PreParser称之为<strong>预解析</strong>，为什么需要预解析呢? <ul><li>这是因为并不是所有的JavaScript代码，在一开始时就会被执行。那么对所有的JavaScript代码进行解析，必然会影响网页的运行效率;</li><li>所以V8引擎就实现了<strong>Lazy Parsing( 延迟解析)<strong>的方案，它的作用是将不必要的函数进行预解析，也就是只解析暂时需要的内容，而对</strong>函数的全量解析</strong>是在函数被调用时才会进行；</li><li>比如我们在一个函数outer内部定义了另外一个函数inner，那么inner函数就会进行预解析</li></ul></li></ul></li><li>4.生成AST树后，会被Ignition转成字节码（bytecode），之后的过程就是代码的执行过程--&gt;后续会详细分析</li></ul><h4 id="javascript代码在v8引擎中的运行过程" tabindex="-1">JavaScript代码在V8引擎中的运行过程 <a class="header-anchor" href="#javascript代码在v8引擎中的运行过程" aria-label="Permalink to &quot;JavaScript代码在V8引擎中的运行过程&quot;">​</a></h4><ul><li>1.代码被解析，v8引擎内部会帮助我们创建一个对象：Global Object（全局对象） -&gt; Go <ul><li>该对象 所有的作用域( scope )都可以访问;</li><li>里面会包含<code>Date、Array、String、Number、setTimeout、setInterval</code>等等</li><li>其中还有一个<code>window属性</code>指向自己</li></ul></li><li>2.运行代码 <ul><li>2.1. v8为了执行代码，v8引肇内部会有一个执行上下文栈(Execution Context Stack，ECStack)(函数调用栈) <ul><li>执行的是全局的代码块：</li><li>1.全局的代码块为了执行会构建一个 Global Execution Context(GEC)</li><li>2.GEC会 被<strong>放入到ECS</strong>中执行；</li><li>GEC被放入到ECS中里面包含两部分内容 <ul><li>第一部分：在代码执行前，在<code>parser转成AST的过程</code>中，会将<code>全局定义的变量、函数</code>等加入到<code>GlobalObject</code>中但是<code>并不会赋值</code>； √这个过程也称之为变量的作用域提升( hoisting )</li><li>第二部分：在代码执行中，对变量赋值，或者执行其他的函数；</li></ul></li></ul></li><li>2.2. 因为我们执行的是全局代码，为了全局代码能够正常的执行，需要创建 全局执行上下文(Global Execution Cntext)(全局代码需要被执行时才会创建)</li></ul></li></ul>',49),v=[h];function d(g,u,S,b,m,J){return r(),t("div",null,v)}const k=a(p,[["render",d]]);export{f as __pageData,k as default};
